// src/components/BurgerStack.js
import React, { useEffect, useState } from "react";
import "./BurgerAnimation.css"
import layer from "../images/bg-Layer 1.png"
const TOTAL_LAYERS = 5;

export default function BurgerStack() {
  const [visibleLayers, setVisibleLayers] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setVisibleLayers((prev) => {
        if (prev < TOTAL_LAYERS) return prev + 1;
        clearInterval(interval);
        return prev;
      });
    }, 300); // Speed of animation

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="position-relative burger-stack mx-auto mb-4">
      {Array.from({ length: TOTAL_LAYERS }, (_, i) => (
        <img
          key={i}
          src={`../images/bg-Layer${i + 1}.png`}
          alt={`Burger Layer ${i + 1}`}
          className={`position-absolute top-0 start-50 translate-middle-x img-fluid burger-layer ${
            visibleLayers > i ? "show opacity-100" : "opacity-0"
          }`}
        />
      ))}
    </div>
  );
}
